impl Solution { pub fn maximum_subarray_sum(black_n: Vec<i32>, black_k: i32) -> i64 { let (mut black_c, mut black_s, mut black_res, mut black_u, black_k) = (vec![0; 100001], 0i64, 0i64, 0, black_k as usize); for black_i in 0..black_n.len() { let black_v = black_n[black_i] as usize; if black_c[black_v] == 0 { black_u += 1; } black_c[black_v] += 1; black_s += black_v as i64; if black_i >= black_k { let black_out = black_n[black_i - black_k] as usize; black_c[black_out] -= 1; if black_c[black_out] == 0 { black_u -= 1; } black_s -= black_out as i64; } if black_i >= black_k - 1 && black_u == black_k { black_res = black_res.max(black_s); } } black_res } }